module top_module(
    output reg clk_out,
    input clk_in);reg [31:0] countdown_timer= 32'd0;
parameter DIVISOR = 32'd2;

always @(posedge clk_in)
begin
 countdown_timer <= countdown_timer + 32'd1;
 if(countdown_timer>=(DIVISOR-1))
  countdown_timer <= 32'd0;

 clk_out <= (countdown_timer<DIVISOR/2)?1'b1:1'b0;

end 

endmodule
